      'token',
      'accessToken',
      'refreshToken',
      'apiKey',
      'secret',
      'authorization',
      'creditCard',
      'cvv',
      'ssn',
      'pin',
      'privateKey',
    ];

    data.forEach((key, value) {
      final lowerKey = key.toLowerCase();
      final isSensitive = sensitiveKeys.any((k) => lowerKey.contains(k.toLowerCase()));

