class LogEntry {
  final DateTime timestamp;
  final LogLevel level;
  final LogCategory category;
  final String message;
  final Map<String, dynamic>? metadata;
  final Object? error;
  final StackTrace? stackTrace;

  LogEntry({
    required this.timestamp,
    required this.level,
    required this.category,
    required this.message,
    this.metadata,
    this.error,
    this.stackTrace,
  });

  Map<String, dynamic> toJson() => {
        'timestamp': timestamp.toIso8601String(),
        'level': level.name,
        'category': category.name,
        'message': message,
        if (metadata != null) 'metadata': metadata,
        if (error != null) 'error': error.toString(),
        if (stackTrace != null) 'stackTrace': stackTrace.toString(),
      };
}

class SecureHttpClient {
  final http.Client _client;
  final SecureLogger _logger = SecureLogger();

  SecureHttpClient({http.Client? client}) : _client = client ?? http.Client();

  Future<http.Response> get(
    Uri url, {
    Map<String, String>? headers,
  }) async {
    return _executeRequest(
      () => _client.get(url, headers: headers),
      'GET',
      url,
      headers,
    );
  }

  Future<http.Response> post(
    Uri url, {
    Map<String, String>? headers,
    Object? body,
  }) async {
    return _executeRequest(
      () => _client.post(url, headers: headers, body: body),
      'POST',
      url,
      headers,
      body,
    );
  }

  Future<http.Response> put(
    Uri url, {
    Map<String, String>? headers,
    Object? body,
  }) async {
    return _executeRequest(
      () => _client.put(url, headers: headers, body: body),
      'PUT',
      url,
      headers,
      body,
    );
  }

  Future<http.Response> delete(
    Uri url, {
    Map<String, String>? headers,
  }) async {
    return _executeRequest(
      () => _client.delete(url, headers: headers),
      'DELETE',
      url,
      headers,
    );
  }

  Future<http.Response> _executeRequest(
    Future<http.Response> Function() request,
    String method,
    Uri url,
    Map<String, String>? headers, [
    Object? body,
  ]) async {
    final requestId = DateTime.now().millisecondsSinceEpoch.toString();
    final startTime = DateTime.now();

    _logger.log(
      'HTTP Request: $method ${url.toString()}',
      level: LogLevel.info,
      category: LogCategory.http,
      metadata: {
        'requestId': requestId,
        'method': method,
        'url': url.toString(),
        'headers': headers ?? {},
        if (body != null) 'bodyLength': body.toString().length,
      },
    );

    try {
      final response = await request();
      final duration = DateTime.now().difference(startTime);

      _logger.log(
        'HTTP Response: $method ${url.toString()} - ${response.statusCode}',
        level: response.statusCode >= 400 ? LogLevel.warning : LogLevel.info,
        category: LogCategory.http,
        metadata: {
          'requestId': requestId,
          'statusCode': response.statusCode,
          'duration': '${duration.inMilliseconds}ms',
          'responseLength': response.body.length,
        },
      );

      return response;
    } catch (e, stackTrace) {
      final duration = DateTime.now().difference(startTime);

      _logger.log(
        'HTTP Request Failed: $method ${url.toString()}',
        level: LogLevel.error,
        category: LogCategory.http,
        metadata: {
          'requestId': requestId,
          'duration': '${duration.inMilliseconds}ms',
        },
        error: e,
        stackTrace: stackTrace,
      );

      rethrow;
    }
  }

  void close() {
    _client.close();
  }
}

